export declare const code_functions = "\n{\"type\": \"function\", \"name\": \"execute_bash\", \"description\": \"Execute a bash command in the terminal.\n* Long running commands: For commands that may run indefinitely, it should be run in the background and the output should be redirected to a file, e.g. command = `python3 app.py > server.log 2>&1 &`.\n* One command at a time: You can only execute one bash command at a time. If you need to run multiple commands sequentially, you can use `&&` or `;` to chain them together.\n\", \"parameters\": {\"type\": \"object\", \"properties\": {\"command\": {\"type\": \"string\", \"description\": \"The bash command to execute. Can be empty string to view additional logs when previous exit code is `-1`. Can be `C-c` (Ctrl+C) to interrupt the currently running process. Note: You can only execute one bash command at a time. If you need to run multiple commands sequentially, you can use `&&` or `;` to chain them together.\"}}, \"required\": [\"command\"]}}\n{\"type\": \"function\", \"name\": \"str_replace_editor\", \"description\": \"Custom editing tool for viewing, creating and editing files in plain-text format\n* State is persistent across command calls and discussions with the user\n* If `path` is a file, `view` displays the result of applying `cat -n`. If `path` is a directory, `view` lists non-hidden files and directories up to 2 levels deep\n* The `create` command cannot be used if the specified `path` already exists as a file\n* If a `command` generates a long output, it will be truncated and marked with `<response clipped>`\n* The `undo_edit` command will revert the last edit made to the file at `path`\n\nNotes for using the `str_replace` command:\n* The `old_str` parameter should match EXACTLY one or more consecutive lines from the original file. Be mindful of whitespaces!\n* If the `old_str` parameter is not unique in the file, the replacement will not be performed. Make sure to include enough context in `old_str` to make it unique\n* The `new_str` parameter should contain the edited lines that should replace the `old_str`\n\", \"parameters\": {\"type\": \"object\", \"properties\": {\"command\": {\"description\": \"The commands to run. Allowed options are: `view`, `create`, `str_replace`, `insert`, `undo_edit`.\", \"enum\": [\"view\", \"create\", \"str_replace\", \"insert\", \"undo_edit\"], \"type\": \"string\"}, \"path\": {\"description\": \"Absolute path to file or directory, e.g. `/workspace/file.py` or `/workspace`.\", \"type\": \"string\"}, \"file_text\": {\"description\": \"Required parameter of `create` command, with the content of the file to be created.\", \"type\": \"string\"}, \"old_str\": {\"description\": \"Required parameter of `str_replace` command containing the string in `path` to replace.\", \"type\": \"string\"}, \"new_str\": {\"description\": \"Optional parameter of `str_replace` command containing the new string (if not given, no string will be added). Required parameter of `insert` command containing the string to insert.\", \"type\": \"string\"}, \"insert_line\": {\"description\": \"Required parameter of `insert` command. The `new_str` will be inserted AFTER the line `insert_line` of `path`.\", \"type\": \"integer\"}, \"view_range\": {\"description\": \"Optional parameter of `view` command when `path` points to a file. If none is given, the full file is shown. If provided, the file will be shown in the indicated line number range, e.g. [11, 12] will show lines 11 and 12. Indexing at 1 to start. Setting `[start_line, -1]` shows all lines from `start_line` to the end of the file.\", \"items\": {\"type\": \"integer\"}, \"type\": \"array\"}}, \"required\": [\"command\", \"path\"]}}\n{\"type\": \"function\", \"name\": \"JupyterCI\", \"parameters\": {\"type\": \"object\", \"properties\": {\"code\": {\"type\": \"string\", \"description\": \"code\"}, \"timeout\": {\"type\": \"integer\", \"description\": \"timeout in seconds\"}}, \"required\": [\"code\"]}, \"description\": \" JupyterCI \u4E00\u4E2A\u4FDD\u7559\u72B6\u6001\u7684\u4EE3\u7801\u6C99\u76D2\u5DE5\u5177\u3002\u4F60\u53EF\u4EE5\u5728\u6B64\u5DE5\u5177\u4E2D\u8FD0\u884Cpython\u4EE3\u7801\"}\n";
